import Card from '../../components/ui/Card.tsx'

interface Metric {
  label: string
  value: string
  description: string
}

const metrics: Metric[] = [
  {
    label: 'Citations totales',
    value: '1 284',
    description: 'Nombre total de citations détectées',
  },
  {
    label: 'Modèles IA',
    value: '4',
    description: 'ChatGPT, Claude, Perplexity, Gemini',
  },
  {
    label: 'Score de visibilité',
    value: '72 %',
    description: 'Taux de présence dans les réponses IA',
  },
  {
    label: 'Tendance',
    value: '+12 %',
    description: 'Évolution sur les 30 derniers jours',
  },
]

export default function DashboardPage() {
  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-900">Tableau de bord</h2>

      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
        {metrics.map((metric) => (
          <Card key={metric.label}>
            <p className="text-sm text-gray-500">{metric.label}</p>
            <p className="mt-1 text-3xl font-bold text-gray-900">
              {metric.value}
            </p>
            <p className="mt-1 text-xs text-gray-400">{metric.description}</p>
          </Card>
        ))}
      </div>
    </div>
  )
}

import { BrowserRouter, Routes, Route, Navigate, Outlet } from 'react-router-dom'
import { AuthProvider, useAuth } from './hooks/useAuth.tsx'
import AuthLayout from './components/layout/AuthLayout.tsx'
import DashboardLayout from './components/layout/DashboardLayout.tsx'
import LoginPage from './pages/auth/LoginPage.tsx'
import RegisterPage from './pages/auth/RegisterPage.tsx'
import ForgotPasswordPage from './pages/auth/ForgotPasswordPage.tsx'
import DashboardPage from './pages/app/DashboardPage.tsx'
import MonitoringPage from './pages/app/MonitoringPage.tsx'
import AnalyticsPage from './pages/app/AnalyticsPage.tsx'
import SettingsPage from './pages/app/SettingsPage.tsx'

function ProtectedRoute() {
  const { isAuthenticated, isLoading } = useAuth()

  if (isLoading) {
    return (
      <div className="flex h-screen items-center justify-center bg-gray-50">
        <p className="text-gray-500">Chargement...</p>
      </div>
    )
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" replace />
  }

  return <Outlet />
}

function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <Routes>
          {/* Routes d'authentification */}
          <Route element={<AuthLayout />}>
            <Route path="/login" element={<LoginPage />} />
            <Route path="/register" element={<RegisterPage />} />
            <Route path="/forgot-password" element={<ForgotPasswordPage />} />
          </Route>

          {/* Routes protégées de l'application */}
          <Route element={<ProtectedRoute />}>
            <Route path="/app" element={<DashboardLayout />}>
              <Route index element={<DashboardPage />} />
              <Route path="monitoring" element={<MonitoringPage />} />
              <Route path="analytics" element={<AnalyticsPage />} />
              <Route path="settings" element={<SettingsPage />} />
            </Route>
          </Route>

          {/* Redirection par défaut */}
          <Route path="*" element={<Navigate to="/login" replace />} />
        </Routes>
      </AuthProvider>
    </BrowserRouter>
  )
}

export default App

import type { ReactNode } from 'react'

interface CardProps {
  title?: string
  children: ReactNode
  className?: string
}

export default function Card({ title, children, className = '' }: CardProps) {
  return (
    <div className={`rounded-xl bg-white p-6 shadow-sm ${className}`}>
      {title && (
        <h3 className="mb-4 text-lg font-semibold text-gray-900">{title}</h3>
      )}
      {children}
    </div>
  )
}

import { Link, useLocation } from 'react-router-dom'

interface NavItem {
  label: string
  path: string
  icon: string
}

const navItems: NavItem[] = [
  { label: 'Tableau de bord', path: '/app', icon: '##' },
  { label: 'Monitoring', path: '/app/monitoring', icon: '~~' },
  { label: 'Analytiques', path: '/app/analytics', icon: '&&' },
  { label: 'Paramètres', path: '/app/settings', icon: '@@' },
]

export default function Sidebar() {
  const location = useLocation()

  function isActive(path: string): boolean {
    if (path === '/app') {
      return location.pathname === '/app'
    }
    return location.pathname.startsWith(path)
  }

  return (
    <aside className="flex h-screen w-64 flex-col bg-gray-900 text-white">
      {/* Logo */}
      <div className="flex h-16 items-center px-6">
        <span className="text-xl font-bold">CitedBy.ai</span>
      </div>

      {/* Navigation */}
      <nav className="mt-4 flex-1 space-y-1 px-3">
        {navItems.map((item) => (
          <Link
            key={item.path}
            to={item.path}
            className={`flex items-center gap-3 rounded-lg px-3 py-2 text-sm font-medium transition-colors ${
              isActive(item.path)
                ? 'bg-blue-600 text-white'
                : 'text-gray-300 hover:bg-gray-800 hover:text-white'
            }`}
          >
            <span className="font-mono text-xs">{item.icon}</span>
            {item.label}
          </Link>
        ))}
      </nav>
    </aside>
  )
}

