import { useState, useMemo } from 'react'
import type { DateRange } from '../types/analytics'
import {
  analyticsOverview,
  monthlyTrends,
  dailyMetrics,
  modelMetrics,
  trackedQueries,
  recentCitations,
  aiModels,
} from '../data/mockAnalytics'

export function useAnalytics() {
  const [dateRange, setDateRange] = useState<DateRange>('30d')
  const [isLoading] = useState(false)

  const filteredDailyMetrics = useMemo(() => {
    const days = dateRange === '7d' ? 7 : dateRange === '30d' ? 30 : 30
    return dailyMetrics.slice(-days)
  }, [dateRange])

  const filteredMonthlyTrends = useMemo(() => {
    const months =
      dateRange === '7d' ? 1
      : dateRange === '30d' ? 3
      : dateRange === '90d' ? 6
      : dateRange === '6m' ? 6
      : 12
    return monthlyTrends.slice(-months)
  }, [dateRange])

  return {
    dateRange,
    setDateRange,
    isLoading,
    overview: analyticsOverview,
    dailyMetrics: filteredDailyMetrics,
    monthlyTrends: filteredMonthlyTrends,
    modelMetrics,
    trackedQueries,
    recentCitations,
    aiModels,
  }
}

