import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts'
import type { ModelMetric } from '../../types/analytics'
import Card from '../ui/Card'

interface ModelDistributionChartProps {
  data: ModelMetric[]
}

function CustomTooltip({ active, payload }: {
  active?: boolean
  payload?: Array<{ payload: ModelMetric }>
}) {
  if (!active || !payload?.[0]) return null
  const d = payload[0].payload
  return (
    <div className="rounded-lg border border-gray-100 bg-white p-3 shadow-lg">
      <p className="text-sm font-semibold text-gray-900">{d.displayName}</p>
      <p className="text-xs text-gray-500">{d.citations} requêtes analysées</p>
      <p className="text-xs text-gray-500">{d.citedCount} citations obtenues</p>
      <p className="text-xs font-semibold" style={{ color: d.color }}>
        Taux: {d.citationRate}%
      </p>
    </div>
  )
}

export default function ModelDistributionChart({ data }: ModelDistributionChartProps) {
  const total = data.reduce((sum, d) => sum + d.citations, 0)

  return (
    <Card title="Répartition par modèle IA">
      <div className="flex items-center gap-4">
        <div className="h-52 w-52 flex-shrink-0">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={data}
                cx="50%"
                cy="50%"
                innerRadius={50}
                outerRadius={80}
                paddingAngle={3}
                dataKey="citations"
                strokeWidth={0}
              >
                {data.map((entry) => (
                  <Cell key={entry.model} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip content={<CustomTooltip />} />
            </PieChart>
          </ResponsiveContainer>
        </div>
        <div className="flex-1 space-y-3">
          {data.map((model) => {
            const pct = ((model.citations / total) * 100).toFixed(1)
            return (
              <div key={model.model} className="flex items-center gap-3">
                <div
                  className="h-3 w-3 flex-shrink-0 rounded-full"
                  style={{ backgroundColor: model.color }}
                />
                <div className="flex-1">
                  <div className="flex items-baseline justify-between">
                    <span className="text-sm font-medium text-gray-900">
                      {model.displayName}
                    </span>
                    <span className="text-xs text-gray-500">{pct}%</span>
                  </div>
                  <div className="mt-1 h-1.5 w-full rounded-full bg-gray-100">
                    <div
                      className="h-1.5 rounded-full transition-all"
                      style={{
                        width: `${pct}%`,
                        backgroundColor: model.color,
                      }}
                    />
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      </div>
    </Card>
  )
}

