import { motion } from 'framer-motion'
import type { TrackedQuery } from '../../types/analytics'
import Card from '../ui/Card'

interface TopQueriesTableProps {
  data: TrackedQuery[]
}

export default function TopQueriesTable({ data }: TopQueriesTableProps) {
  const getTrendIcon = (trend: TrackedQuery['trend']) => {
    switch (trend) {
      case 'up': return { symbol: '\u2191', class: 'text-emerald-500' }
      case 'down': return { symbol: '\u2193', class: 'text-red-500' }
      default: return { symbol: '\u2192', class: 'text-gray-400' }
    }
  }

  const getRateColor = (rate: number) => {
    if (rate >= 70) return 'bg-emerald-100 text-emerald-700'
    if (rate >= 50) return 'bg-amber-100 text-amber-700'
    return 'bg-red-100 text-red-700'
  }

  return (
