import { motion } from 'framer-motion'
import type { Citation } from '../../types/analytics'
import { aiModels } from '../../data/mockAnalytics'
import Card from '../ui/Card'

interface RecentCitationsTableProps {
  data: Citation[]
}

export default function RecentCitationsTable({ data }: RecentCitationsTableProps) {
  const getModelColor = (modelName: string) => {
    const model = aiModels.find(
      (m) => m.displayName.toLowerCase() === modelName.toLowerCase()
    )
    return model?.color ?? '#6b7280'
  }

  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr)
    const now = new Date()
    const diffMs = now.getTime() - date.getTime()
    const diffH = Math.floor(diffMs / (1000 * 60 * 60))

    if (diffH < 1) return "Il y a moins d'1h"
    if (diffH < 24) return `Il y a ${diffH}h`
    const diffD = Math.floor(diffH / 24)
    if (diffD === 1) return 'Hier'
    return `Il y a ${diffD}j`
  }

  return (
    <Card title="Dernières citations détectées">
      <div className="space-y-3">
        {data.slice(0, 6).map((citation, i) => (
          <motion.div
            key={citation.id}
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.05 }}
            className="flex items-center gap-3 rounded-lg border border-gray-50 p-3 hover:bg-gray-50"
          >
            <div
              className="flex h-9 w-9 flex-shrink-0 items-center justify-center rounded-lg text-xs font-bold text-white"
              style={{ backgroundColor: getModelColor(citation.modelName) }}
            >
              {citation.modelName.slice(0, 2).toUpperCase()}
            </div>
            <div className="min-w-0 flex-1">
              <p className="truncate text-sm font-medium text-gray-900">
                {citation.query}
              </p>
              <div className="mt-0.5 flex items-center gap-2">
                <span className="text-xs text-gray-400">{citation.modelName}</span>
                {citation.position && (
                  <span className="text-xs text-gray-400">
                    Position #{citation.position}
                  </span>
                )}
              </div>
            </div>
            <div className="flex flex-col items-end gap-1">
              <span
                className={`inline-block rounded-full px-2 py-0.5 text-xs font-semibold ${
                  citation.cited
                    ? 'bg-emerald-50 text-emerald-600'
                    : 'bg-red-50 text-red-600'
                }`}
              >
                {citation.cited ? 'Cité' : 'Non cité'}
              </span>
              <span className="text-xs text-gray-400">
                {formatDate(citation.detectedAt)}
              </span>
            </div>
          </motion.div>
        ))}
      </div>
    </Card>
  )
}

